import { createZhipuWebSearchTool } from "./search.js";
import type { ZhipuWebSearchConfig } from "./search.js";

export { createZhipuWebSearchTool } from "./search.js";
export type { ZhipuWebSearchConfig } from "./search.js";

type PluginApi = {
  pluginConfig?: Record<string, unknown>;
  registerTool: (tool: unknown, opts?: { name?: string }) => void;
  [key: string]: unknown;
};

const plugin = {
  id: "openclaw-web-search",
  name: "Web Search (Zhipu)",
  description: "Web search via Zhipu AI API, accessible from within China",
  register(api: PluginApi) {
    const config = (api.pluginConfig ?? {}) as ZhipuWebSearchConfig;
    if (config.enabled === false) return;
    api.registerTool(createZhipuWebSearchTool(config), {
      name: "web_search",
    });
  },
};

export default plugin;
