import { Type } from "@sinclair/typebox";

// ─── Types ──────────────────────────────────────────────────

export type ZhipuWebSearchConfig = {
  enabled?: boolean;
  apiKey?: string;
  baseUrl?: string;
  searchEngine?: string;
  maxResults?: number;
  contentSize?: string;
};

type ZhipuSearchResult = {
  title: string;
  content: string;
  link: string;
  media?: string;
  publish_date?: string;
};

type ZhipuSearchResponse = {
  search_result?: ZhipuSearchResult[];
};

// ─── Parameter Schema ───────────────────────────────────────

const ZhipuWebSearchSchema = Type.Object({
  query: Type.String({ description: "Search query string." }),
  count: Type.Optional(
    Type.Number({
      description: "Number of results to return (1-10).",
      minimum: 1,
      maximum: 10,
    })
  ),
  search_lang: Type.Optional(
    Type.String({
      description:
        "Language for search results (e.g., 'zh', 'en'). Defaults to auto-detect.",
    })
  ),
  freshness: Type.Optional(
    Type.String({
      description:
        'Filter by recency: "oneDay", "oneWeek", "oneMonth", "threeMonths", "sixMonths", "oneYear", or "noLimit" (default).',
    })
  ),
});

// ─── Freshness mapping ──────────────────────────────────────

const FRESHNESS_MAP: Record<string, string> = {
  pd: "oneDay",
  pw: "oneWeek",
  pm: "oneMonth",
  oneday: "oneDay",
  oneweek: "oneWeek",
  onemonth: "oneMonth",
  threemonths: "threeMonths",
  sixmonths: "sixMonths",
  oneyear: "oneYear",
  nolimit: "noLimit",
};

function normalizeFreshness(raw?: string): string {
  if (!raw) return "noLimit";
  const key = raw.toLowerCase().replace(/[-_\s]/g, "");
  return FRESHNESS_MAP[key] ?? raw;
}

// ─── Format results ─────────────────────────────────────────

function formatResults(query: string, results: ZhipuSearchResult[]): string {
  if (!results.length) {
    return `Web search results for: "${query}"\n\nNo results found.`;
  }

  const lines = [`Web search results for: "${query}"\n`];

  for (let i = 0; i < results.length; i++) {
    const r = results[i];
    lines.push(`${i + 1}. ${r.title}`);
    lines.push(`   URL: ${r.link}`);
    const meta: string[] = [];
    if (r.media) meta.push(`Source: ${r.media}`);
    if (r.publish_date) meta.push(`Date: ${r.publish_date}`);
    if (meta.length) lines.push(`   ${meta.join(" | ")}`);
    if (r.content) lines.push(`   Summary: ${r.content}`);
    lines.push("");
  }

  return lines.join("\n");
}

// ─── Resolve API key ────────────────────────────────────────

function resolveApiKey(config: ZhipuWebSearchConfig): string | undefined {
  return (
    config.apiKey ||
    process.env.ZHIPU_API_KEY ||
    process.env.ZAI_API_KEY ||
    undefined
  );
}

// ─── Tool factory ───────────────────────────────────────────

export function createZhipuWebSearchTool(config: ZhipuWebSearchConfig) {
  const apiKey = resolveApiKey(config);
  const baseUrl = (config.baseUrl ?? "https://open.bigmodel.cn").replace(
    /\/+$/,
    ""
  );
  const searchEngine = config.searchEngine ?? "search_std";
  const maxResults = config.maxResults ?? 10;
  const contentSize = config.contentSize ?? "medium";

  return {
    label: "Web Search",
    name: "web_search",
    description:
      "Search the web for current information. Returns a list of relevant results with titles, URLs, and summaries. Use this when you need up-to-date information or to answer questions about recent events.",
    parameters: ZhipuWebSearchSchema,
    async execute(
      _toolCallId: string,
      params: Record<string, unknown>
    ): Promise<{ content: Array<{ type: "text"; text: string }>; details: unknown }> {
      const query = (params.query as string | undefined)?.trim();
      if (!query) {
        return {
          content: [{ type: "text" as const, text: "Error: query is required." }],
          details: { error: "query is required" },
        };
      }

      const resolvedKey = resolveApiKey(config);
      if (!resolvedKey) {
        return {
          content: [
            {
              type: "text" as const,
              text: "Error: Zhipu API key not configured. Set apiKey in plugin config or ZHIPU_API_KEY / ZAI_API_KEY environment variable.",
            },
          ],
          details: { error: "api_key_missing" },
        };
      }

      const count = Math.min(
        Math.max(Math.round(Number(params.count) || maxResults), 1),
        10
      );
      const freshness = normalizeFreshness(params.freshness as string | undefined);

      const body: Record<string, unknown> = {
        search_query: query,
        search_engine: searchEngine,
        count,
        search_recency_filter: freshness,
        content_size: contentSize,
      };
      if (params.search_lang) {
        body.search_lang = params.search_lang;
      }

      const url = `${baseUrl}/api/paas/v4/web_search`;

      let resp: Response;
      try {
        resp = await fetch(url, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${resolvedKey}`,
          },
          body: JSON.stringify(body),
        });
      } catch (err: unknown) {
        const msg =
          err instanceof Error ? err.message : "Unknown network error";
        return {
          content: [
            { type: "text" as const, text: `Error: Failed to reach Zhipu API: ${msg}` },
          ],
          details: { error: msg },
        };
      }

      if (!resp.ok) {
        let errText: string;
        try {
          errText = await resp.text();
        } catch {
          errText = resp.statusText;
        }
        return {
          content: [
            {
              type: "text" as const,
              text: `Error: Zhipu API returned ${resp.status}: ${errText}`,
            },
          ],
          details: { error: errText, status: resp.status },
        };
      }

      let data: ZhipuSearchResponse;
      try {
        data = (await resp.json()) as ZhipuSearchResponse;
      } catch {
        return {
          content: [
            { type: "text" as const, text: "Error: Failed to parse Zhipu API response." },
          ],
          details: { error: "json_parse_error" },
        };
      }

      const results = data.search_result ?? [];
      const text = formatResults(query, results);

      return {
        content: [{ type: "text" as const, text }],
        details: { resultCount: results.length, query },
      };
    },
  };
}
